"""Eval harness: triage confusion matrix over labeled messages.

The metric that decides a release: false AUTO_BOOK must be zero. A wrong
auto-booked order dispatches a truck to the wrong place; a REVIEW that
could have auto-booked costs one human confirmation. Not symmetric.
"""
from intake import normalize
from extract import extract
from triage import triage
from fixtures import MESSAGES, LABELS

# extra labeled variations, generated by mutating the base fixtures
VARIATIONS = []
for i, (origin, dest) in enumerate([("dubai", "muscat"), ("jeddah", "neom"),
                                    ("doha", "dammam"), ("sharjah", "riyadh")]):
    VARIATIONS += [
        {"id": f"VAR-{i}A", "channel": "text", "expected": "AUTO_BOOK",
         "body": f"need 4 reefer truck {origin} to {dest} on 28/07 chemicals"},
        {"id": f"VAR-{i}B", "channel": "voice", "expected": "REVIEW",
         "body": f"uh need trucks {origin} to {dest} maybe friday steel"},
        {"id": f"VAR-{i}C", "channel": "ocr", "expected": "REJECT",
         "body": "STATEMENT OF ACCOUNT balance due 45 days please remit"},
    ]


def run():
    cases = [dict(m, expected=LABELS[m["id"]]) for m in MESSAGES] + VARIATIONS
    matrix = {}
    false_autobook = []
    for case in cases:
        got = triage(extract(normalize(case)))["decision"]
        matrix[(case["expected"], got)] = matrix.get((case["expected"], got), 0) + 1
        if got == "AUTO_BOOK" and case["expected"] != "AUTO_BOOK":
            false_autobook.append(case["id"])

    labels = ("AUTO_BOOK", "REVIEW", "REJECT")
    print(f"{len(cases)} labeled messages\n")
    print(f"{'expected/got':<14}" + "".join(f"{l:>11}" for l in labels))
    for exp in labels:
        print(f"{exp:<14}" + "".join(f"{matrix.get((exp, got), 0):>11}" for got in labels))
    correct = sum(matrix.get((l, l), 0) for l in labels)
    print(f"\ntriage accuracy {correct / len(cases):.2f}")
    print(f"false AUTO_BOOK: {len(false_autobook)} of {len(cases)}  {false_autobook or ''}")
    return len(false_autobook)


if __name__ == "__main__":
    assert run() == 0, "false AUTO_BOOK is the failure mode this pipeline must never have"
